async function main() {
  await connectDB();

  if (mode === "posters") {
    let count = 0;
    for (const [title, data] of Object.entries(posterFixes)) {
      const game = await Game.findOne({ title });
      if (!game) { console.log(`NOT FOUND: ${title}`); continue; }
      await Game.findByIdAndUpdate(game._id, { $set: { poster: data.poster, screenshots: data.screenshots } });
      console.log(`\u2713 ${title}`);
      count++;
    }
    console.log(`\nUpdated ${count} games`);
  }

  if (mode === "descriptions") {
    let count = 0;
    for (const [title, description] of Object.entries(descriptions)) {
      const game = await Game.findOne({ title });
      if (!game) { console.log(`NOT FOUND: ${title}`); continue; }
      const existing = game.screenshots || [];
      let screenshots = [...existing];
      if (screenshots.length === 0 && game.poster) screenshots = [game.poster];
      if (screenshots.length === 1 && game.poster && !screenshots.includes(game.poster)) screenshots.unshift(game.poster);
      await Game.findByIdAndUpdate(game._id, { $set: { description, screenshots } });
      console.log(`\u2713 ${title}`);
      count++;
    }
    console.log(`\nUpdated ${count} games`);
  }

  if (mode === "details") {
    let updated = 0;
    for (const data of gameDetails) {
      const result = await Game.findOneAndUpdate(
        { title: data.title },
        { $set: { publisher: data.publisher, highlights: data.highlights } },
        { new: true }
      );
      if (result) {
        console.log(`\u2713 ${result.title}`);
        updated++;
      } else {
        console.log(`\u2717 ${data.title} \u2014 not found`);
      }
    }
    console.log(`\nUpdated ${updated}/${gameDetails.length} games`);
  }

  process.exit(0);
}

main();
